import{_ as l,c as i,o as a,a4 as e}from"./chunks/framework.HaEZziQ1.js";const b=JSON.parse('{"title":"模拟面试","description":"","frontmatter":{},"headers":[],"relativePath":"Document/前端面试相关/模拟面试.md","filePath":"Document/前端面试相关/模拟面试.md","lastUpdated":1709727320000}'),p={name:"Document/前端面试相关/模拟面试.md"},r=e('<h1 id="模拟面试" tabindex="-1">模拟面试 <a class="header-anchor" href="#模拟面试" aria-label="Permalink to &quot;模拟面试&quot;">​</a></h1><p><a href="https://github.com/AnsonZnl/interview-nav" target="_blank" rel="noreferrer">AnsonZnl/interview-nav: 面试网站导航，收集 IT 行业各个岗位的优质面试题网站、简历编写指南。 (github.com)</a></p><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><ul><li>⾃我介绍</li><li>⾯试完你还有什么问题要问的吗</li><li>你有什么爱好?</li><li>你最⼤的优点和缺点是什么?</li><li>你为什么会选择这个⾏业，职位?</li><li>你觉得你适合从事这个岗位吗?</li><li>你有什么职业规划?</li><li>你对⼯资有什么要求?</li><li>如何看待前端开发？</li><li>未来三到五年的规划是怎样的？</li><li>你的项⽬中技术难点是什么？遇到了什么问题？你是怎么解决的？</li><li>你们部⻔的开发流程是怎样的</li><li>你认为哪个项⽬做得最好？</li><li>说下⼯作中你做过的⼀些性能优化处理</li><li>最近在看哪些前端⽅⾯的书？</li><li>平时是如何学习前端开发的？</li><li>你最有成就感的⼀件事</li><li>你为什么要离开前⼀家公司？</li><li>你对加班的看法</li><li>你希望通过这份⼯作获得什么？</li></ul><h2 id="一面" tabindex="-1">一面 <a class="header-anchor" href="#一面" aria-label="Permalink to &quot;一面&quot;">​</a></h2><p>前端的html + css + javascript基础知识 + 框架的基本使用</p><p>重基础、懂原理，要思考、知进退、势不可挡</p><ul><li>准备要充分</li><li>知识要系统</li><li>沟通要简洁</li><li>内心要诚实</li><li>态度要谦虚</li><li>回答要灵活</li></ul><h2 id="二面-三面" tabindex="-1">二面/三面 <a class="header-anchor" href="#二面-三面" aria-label="Permalink to &quot;二面/三面&quot;">​</a></h2><p>继承之上的延伸或者JavaScript|浏览器|Node 运行的原理 + JavaScript的高级特性</p><p>项目怎么样架构，功能怎么实现，使用什么技术栈</p><p>有什么特色业务，推动了什么改变了什么</p><ul><li>知识面要广</li><li>理解要深刻</li><li>内心要诚实</li><li>态度要谦虚</li><li>回答要灵活</li><li>要学会赞美</li></ul><p>横向扩展、项目结合，做到有的放矢</p><p>保证候选人能正常工作---考察使用</p><p>多个候选人竞争时，选择有技术追求的---考察原理</p><p>看候选人是否能独立承担项目---考察设计能力</p><h2 id="三面-四面" tabindex="-1">三面/四面 <a class="header-anchor" href="#三面-四面" aria-label="Permalink to &quot;三面/四面&quot;">​</a></h2><p>有经验、懂合作、有担当、懂规矩、察言观色</p><p>项目设计能力 + 工作经验和环境</p><ul><li>准备要充分</li><li>描述要演练</li><li>引导找时机</li><li>优势要发挥</li><li>回答要灵活</li></ul><h3 id="业务能力" tabindex="-1">业务能力 <a class="header-anchor" href="#业务能力" aria-label="Permalink to &quot;业务能力&quot;">​</a></h3><p>主动描述</p><p>被动回答</p><ul><li>我做过什么业务?</li><li>负责的业务有什么业绩?</li><li>使用了什么技术方案?</li><li>突破了什么技术难点?</li><li>遇到了什么问题?</li><li>最大的收获是什么?</li></ul><p>回答例子：</p><p>独立负责360数据彩票走势图开发</p><p>历时3周完成所有彩种开发，用户量上涨15%</p><p>区别常规canvas方案，使用vml+svg方案</p><p>解决了走势图高级绘图板的开发</p><p>橡皮擦的问题、动态连线计算等</p><p>对业务的理解更加深入、对技术图表更有把控</p><h3 id="团队协作能力" tabindex="-1">团队协作能力 <a class="header-anchor" href="#团队协作能力" aria-label="Permalink to &quot;团队协作能力&quot;">​</a></h3><p>主动描述</p><p>对彩票足彩的奖金算法有深入研究，业内第一为H5、客户端讲解算法并协助完成开发和PHP、PM同学在一天的时间内快速支持足彩竞猜活动和leader独立负责彩票PC站</p><h3 id="事务推动能力" tabindex="-1">事务推动能力 <a class="header-anchor" href="#事务推动能力" aria-label="Permalink to &quot;事务推动能力&quot;">​</a></h3><p>主动描述</p><ul><li>对历史算法更新换代</li><li>推动专题的CMS架构</li><li>主导客服系统的建设</li><li>完成多项专利的申请</li></ul><h3 id="带人能力" tabindex="-1">带人能力 <a class="header-anchor" href="#带人能力" aria-label="Permalink to &quot;带人能力&quot;">​</a></h3><p>主动描述</p><ul><li>带一个社招完成数字彩的开发和维护</li><li>带一个实习生完成专题活动的开发</li><li>代码规范、Review</li></ul><h2 id="hr终面" tabindex="-1">HR终面 <a class="header-anchor" href="#hr终面" aria-label="Permalink to &quot;HR终面&quot;">​</a></h2><p>沟通能力，性格，潜力</p><p>会沟通、要上进、好性格、有主见、强逻辑、无可挑剔</p><ul><li>1、乐观积极</li><li>2、主动沟通</li><li>3、逻辑顺畅</li><li>4、上进有责任心</li><li>5、有主张，做事果断</li></ul><h3 id="_1、职业竞争力" tabindex="-1">1、职业竞争力 <a class="header-anchor" href="#_1、职业竞争力" aria-label="Permalink to &quot;1、职业竞争力&quot;">​</a></h3><p>1、业务能力 可以做到行业第一</p><p>2、思考能力 对同一件事可以从不同角度去思考，找到最优解</p><p>3、学习能力 不断学习新的业务和技术，沉淀、总结</p><p>4、无上限的付出 对于无法解决的问题可以熬夜、加班</p><h3 id="_2、职业规划" tabindex="-1">2、职业规划 <a class="header-anchor" href="#_2、职业规划" aria-label="Permalink to &quot;2、职业规划&quot;">​</a></h3><p>1、目标是什么 在业务上成为专家，在技术上成为行业大牛</p><p>2、近阶段的目标 不断的学习积累各方面的经验，以学习为主</p><p>3、长期目标 做几件很有价值的事情，如开源作品、技术框架等</p><p>4、方式方法 先完成业务上的主要问题，做到极致，然后逐步向目标靠拢</p><h2 id="问公司" tabindex="-1">问公司 <a class="header-anchor" href="#问公司" aria-label="Permalink to &quot;问公司&quot;">​</a></h2><p>职位和薪资晋升制度是怎么样的</p><p>福利制度：社保，上班时间，年假，团建，氛围，薪资构成，年终奖</p><p>了解谈判的技巧和策略</p><p>1、明确谈判目标是谈判的第一步。 2、了解并重视对手。 3、找出真正的决策者或者有影响力的人。 4、进行情感补偿。做到真诚而不虚假，适当调动对方的情绪，给予情感补偿，让对方有赢的感觉。 5、利用定位调整偏见。谈判就是博弈，让对方感受到你做出了很大的让步 6、坦诚相对，谨守道德。</p><p>了解决定薪资的因素和构成</p><p>了解决定一个企业薪资的因素，是我们处理好薪资谈判的基础。</p><p>包括:</p><p>1、行业内的薪资行情。 2、企业内部目前的经营利润情况。 3、公平的分配原则，是不是多劳多得的薪酬制度。 4、薪酬设计是否达到合理标准。 5、以及薪酬除了福利待遇之外，企业是否用薪资对员工进行激励的激励原则。 6、最后就是企业考虑的成本原则，员工的工资是企业成本的最大支出。</p><p>薪资构成：基本工资(底薪)占薪资的 30%-60% + 奖金(绩效) + 提成 + 福利补贴 + 加班费</p><h2 id="理想的工作" tabindex="-1">理想的工作 <a class="header-anchor" href="#理想的工作" aria-label="Permalink to &quot;理想的工作&quot;">​</a></h2><p>一份理想的工作应该满足什么条件?</p><p>发展空间：包括行业发展、职业选择是否有兴趣，是否有发展空间、企业内部的氛围和环境是良性竞争还是潜规则、以及能力与目标岗位的匹配</p><p>企业品牌和规模：公司品牌的影响力公司规模以及行业地位</p><p>企业文化：组织氛困，人际和谐、领导风格，以及企业价值观，是否能够心情愉悦</p><p>能力提升：包括专业技能的提升、工作经验的获取包括岗位经验，项目经验，管理经验以及行业经验、实际锻炼的机会是否能够实现工作的多样化以及综合能力的提升</p><p>薪资待遇：薪酬福利的合理性和公平性以及性价比福利待遇是否齐全，是否关爱员工</p><p>管理规范：管理能力、管理规范以及制度完善。运作效率以及管理方式是否人性化</p><h2 id="面试后的复盘" tabindex="-1">面试后的复盘 <a class="header-anchor" href="#面试后的复盘" aria-label="Permalink to &quot;面试后的复盘&quot;">​</a></h2><p>复盘</p><p>胜不骄、败不馁、总结经验、步步为营、多拿几个offer</p>',76),t=[r];function o(h,n,d,s,c,u){return a(),i("div",null,t)}const m=l(p,[["render",o]]);export{b as __pageData,m as default};
